    #[test]
    fn evidence_bundle_loop_plan_ref_allows_generated_root_locations() {
        use AuthoringLoopEvidenceBundleArtifactKind::LoopPlan;
        // A plan stored under an allowed generated local root validates, matching
        // what the runner accepts for the plan path it executed against.
        validate_authoring_loop_bundle_ref_path("loopPlan", LoopPlan, ".omx/loop-plan.json", &[])
            .expect("generated-root loop plan path allowed");
        // A plain project-relative plan path still validates.
        validate_authoring_loop_bundle_ref_path("loopPlan", LoopPlan, "loop-plan.json", &[])
            .expect("plain loop plan path allowed");
        // Traversal stays rejected.
        assert!(validate_authoring_loop_bundle_ref_path(
            "loopPlan",
            LoopPlan,
            "../escape.json",
            &[]
        )
        .is_err());
    }

    #[test]
    fn authoring_loop_plan_validation_rejects_invalid_rules() {
        for (fixture, expected) in [
            (
                "examples/authoring-loop-plan-fixtures/invalid/duplicate-step-id.json",
                "duplicate authoring loop plan step id",
            ),
            (
                "examples/authoring-loop-plan-fixtures/invalid/out-of-order-step.json",
                "out of order",
            ),
            (
                "examples/authoring-loop-plan-fixtures/invalid/missing-input-artifact.json",
                "must reference an earlier expected artifact",
            ),
            (
                "examples/authoring-loop-plan-fixtures/invalid/incomplete-input-producer.json",
                "is not produced by a completed step",
            ),
            (
                "examples/authoring-loop-plan-fixtures/invalid/invalid-status-transition.json",
                "invalid status transition",
            ),
        ] {
            let input = fs::read_to_string(repo_fixture_path(fixture))
                .unwrap_or_else(|error| panic!("{fixture} reads: {error:#}"));
            let rejected =
                AuthoringLoopPlan::from_json_str(&input).expect_err(&format!("{fixture} rejected"));
            assert!(
                rejected.to_string().contains(expected),
                "{fixture} error {rejected:#} did not contain {expected}"
            );
        }

        assert!(
            AuthoringLoopStepStatus::Pending.can_transition_to(AuthoringLoopStepStatus::Running)
        );
        assert!(
            !AuthoringLoopStepStatus::Pending.can_transition_to(AuthoringLoopStepStatus::Completed)
        );
    }

    #[test]
    fn loop_step_runner_state_machine_updates_status_without_execution() {
        let plan = AuthoringLoopPlan::from_json_str(include_str!(
            "../../../examples/authoring-loop-plan-fixtures/valid/pending.json"
        ))
        .expect("pending loop plan validates");

        let (updated, summary) = plan
            .update_step_status("run-baseline", AuthoringLoopStepStatus::Running)
            .expect("pending step can become running");

        let step = updated
            .steps
            .iter()
            .find(|step| step.id == "run-baseline")
            .expect("updated step present");
        assert_eq!(step.status, AuthoringLoopStepStatus::Running);
        assert_eq!(
            step.status_transition,
            Some(AuthoringLoopStatusTransition {
                from: AuthoringLoopStepStatus::Pending,
                to: AuthoringLoopStepStatus::Running,
            })
        );
        assert_eq!(summary.loop_id, "fixture-loop-pending");
        assert_eq!(summary.step_id, "run-baseline");
        assert_eq!(summary.kind, "run-scenario-pack");
        assert_eq!(summary.from, "pending");
        assert_eq!(summary.to, "running");
        assert_eq!(summary.outcome, "updated");
        assert!(summary.boundary.contains("does not execute commands"));
    }

    #[test]
    fn loop_step_runner_state_machine_blocks_invalid_or_unsafe_transitions() {
        let pending = AuthoringLoopPlan::from_json_str(include_str!(
            "../../../examples/authoring-loop-plan-fixtures/valid/pending.json"
        ))
        .expect("pending loop plan validates");

        let direct_complete = pending
            .update_step_status("run-baseline", AuthoringLoopStepStatus::Completed)
            .expect_err("pending cannot complete without running");
        assert!(direct_complete.to_string().contains("cannot transition"));

        let unmet_dependency = pending
            .update_step_status("summarize", AuthoringLoopStepStatus::Running)
            .expect_err("dependent step cannot run before dependency completes");
        assert!(unmet_dependency.to_string().contains("before dependency"));

        let partial = AuthoringLoopPlan::from_json_str(include_str!(
            "../../../examples/authoring-loop-plan-fixtures/valid/partial.json"
        ))
        .expect("partial loop plan validates");
        let (completed, summary) = partial
            .update_step_status("compare-runs", AuthoringLoopStepStatus::Completed)
            .expect("running step can complete");
        assert_eq!(summary.from, "running");
        assert_eq!(summary.to, "completed");
        assert_eq!(
            completed
                .steps
                .iter()
                .find(|step| step.id == "compare-runs")
                .expect("compare step")
                .status,
            AuthoringLoopStepStatus::Completed
        );
    }

    #[test]
    fn loop_recovery_metadata_serializes_and_preserves_existing_plan_compatibility() {
        let existing = AuthoringLoopPlan::from_json_str(include_str!(
            "../../../examples/authoring-loop-plan-fixtures/valid/pending.json"
        ))
        .expect("existing plan without recovery remains compatible");
        assert!(existing.steps.iter().all(|step| step.recovery.is_none()));

        let mut recovered = existing.clone();
        recovered.steps[1].status = AuthoringLoopStepStatus::Blocked;
        recovered.steps[1].status_transition = Some(AuthoringLoopStatusTransition {
            from: AuthoringLoopStepStatus::Pending,
            to: AuthoringLoopStepStatus::Blocked,
        });
        recovered.steps[1].recovery = Some(AuthoringLoopStepRecovery {
            failure: AuthoringLoopFailureMetadata {
                reason: "missing accepted review decision".to_string(),
                category: Some(AuthoringLoopFailureCategory::ManualGate),
                detail: Some("human review must be recorded before resume".to_string()),
            },
            retryability: AuthoringLoopRetryability::ManualActionRequired,
            manual_action: AuthoringLoopManualAction {
                kind: AuthoringLoopManualActionKind::ProvideDecision,
                description: "Record an accepted or rejected review decision, then rerun explicit resume preflight.".to_string(),
            },
            rollback_refs: vec![AuthoringLoopArtifactRef {
                id: "baseline-run".to_string(),
                path: "runs/baseline/run.json".to_string(),
                description: Some("last safe run before blocked step".to_string()),
            }],
            evidence_refs: vec![AuthoringLoopArtifactRef {
                id: "recovery-evidence".to_string(),
                path: "runs/baseline/ledger.jsonl".to_string(),
                description: Some("loop ledger evidence".to_string()),
            }],
            resume_command: Some(AuthoringLoopResumeCommandContext {
                command: "cargo run -p ouroforge-cli -- loop resume loop-plan.json --step summarize".to_string(),
                argv: vec![
                    "cargo".to_string(),
                    "run".to_string(),
                    "-p".to_string(),
                    "ouroforge-cli".to_string(),
                    "--".to_string(),
                    "loop".to_string(),
                    "resume".to_string(),
                    "loop-plan.json".to_string(),
                    "--step".to_string(),
                    "summarize".to_string(),
                ],
                boundary: "explicit CLI-only resume preflight; browser surfaces display only".to_string(),
            }),
        });
        recovered
            .validate_schema()
            .expect("recovery metadata validates");

        let rendered = serde_json::to_string_pretty(&recovered).expect("recovery serializes");
        assert!(rendered.contains("\"recovery\""));
        assert!(rendered.contains("manual-action-required"));
        assert!(rendered.contains("provide-decision"));

        let reparsed = AuthoringLoopPlan::from_json_str(&rendered).expect("recovery reparses");
        assert_eq!(reparsed, recovered);
    }

    #[test]
    fn loop_recovery_metadata_rejects_empty_reason_or_resume_context() {
        let mut plan = AuthoringLoopPlan::from_json_str(include_str!(
            "../../../examples/authoring-loop-plan-fixtures/valid/pending.json"
        ))
        .expect("pending plan validates");
        // Recovery metadata is only valid on a blocked or failed step.
        plan.steps[0].status = AuthoringLoopStepStatus::Failed;
        plan.steps[0].recovery = Some(AuthoringLoopStepRecovery {
            failure: AuthoringLoopFailureMetadata {
                reason: "".to_string(),
                category: Some(AuthoringLoopFailureCategory::ExecutionError),
                detail: None,
            },
            retryability: AuthoringLoopRetryability::Retryable,
            manual_action: AuthoringLoopManualAction {
                kind: AuthoringLoopManualActionKind::InspectFailure,
                description: "Inspect failure evidence".to_string(),
            },
            rollback_refs: Vec::new(),
            evidence_refs: Vec::new(),
            resume_command: Some(AuthoringLoopResumeCommandContext {
                command:
                    "cargo run -p ouroforge-cli -- loop resume loop-plan.json --step run-baseline"
                        .to_string(),
                argv: Vec::new(),
                boundary: "explicit CLI-only resume preflight".to_string(),
            }),
        });

        let error = plan
            .validate_schema()
            .expect_err("empty recovery reason fails");
        assert!(error.to_string().contains("is required"), "{error:#}");

        let recovery = plan.steps[0].recovery.as_mut().expect("recovery present");
        recovery.failure.reason = "transient preflight failure".to_string();
        let error = plan
            .validate_schema()
            .expect_err("empty resume argv fails after reason fixed");
        assert!(
            error.to_string().contains("argv must not be empty"),
            "{error:#}"
        );

        // Recovery metadata is rejected on a non-blocked/failed step even when its
        // own fields are valid.
        plan.steps[0]
            .recovery
            .as_mut()
            .expect("recovery present")
            .resume_command
            .as_mut()
            .expect("resume command")
            .argv = vec!["loop".to_string(), "resume".to_string()];
        plan.steps[0].status = AuthoringLoopStepStatus::Pending;
        let error = plan
            .validate_schema()
            .expect_err("recovery on pending step rejected");
        assert!(
            error
                .to_string()
                .contains("only allowed on blocked or failed steps"),
            "{error:#}"
        );
    }

    #[test]
    fn accepted_decision_match_requires_explicit_matching_id() {
        let required = "review-decision-1";
        // Matching id plus an accepted state authorizes the decision.
        assert!(json_value_contains_accepted_decision(
            &json!({ "id": required, "state": "accepted" }),
            required
        ));
        // An accepted state with no id must NOT be treated as a match.
        assert!(!json_value_contains_accepted_decision(
            &json!({ "status": "accepted" }),
            required
        ));
        // An accepted state with a different id must not match.
        assert!(!json_value_contains_accepted_decision(
            &json!({ "id": "other", "decisionStatus": "accepted" }),
            required
        ));
        // A nested accepted decision carrying the matching id still matches.
        assert!(json_value_contains_accepted_decision(
            &json!({ "decisions": [{ "id": required, "state": "accepted" }] }),
            required
        ));
    }

    #[test]
    fn loop_recovery_status_and_resume_preflight_report_next_safe_action() {
        let root = unique_temp_dir("loop-recovery-status");
        write_loop_dry_run_project(&root);
        let plan_path = write_loop_dry_run_plan(&root, "loop_project");
        let mut plan = read_loop_plan_from_path(&plan_path);
        plan.steps[1].status = AuthoringLoopStepStatus::Blocked;
        plan.steps[1].status_transition = Some(AuthoringLoopStatusTransition {
            from: AuthoringLoopStepStatus::Pending,
            to: AuthoringLoopStepStatus::Blocked,
        });
        plan.steps[1].recovery = Some(AuthoringLoopStepRecovery {
            failure: AuthoringLoopFailureMetadata {
                reason: "comparison artifact is missing".to_string(),
                category: Some(AuthoringLoopFailureCategory::MissingPrerequisite),
                detail: None,
            },
            retryability: AuthoringLoopRetryability::ManualActionRequired,
            manual_action: AuthoringLoopManualAction {
                kind: AuthoringLoopManualActionKind::RepairMissingArtifact,
                description: "Regenerate the comparison artifact before resume.".to_string(),
            },
            rollback_refs: Vec::new(),
            evidence_refs: Vec::new(),
            resume_command: None,
        });
        write_json(&plan_path, &json!(plan)).expect("recovery plan writes");

        let status = build_authoring_loop_status_from_path(&plan_path).expect("status builds");
        assert_eq!(status.schema_version, AUTHORING_LOOP_STATUS_SCHEMA_VERSION);
        assert_eq!(status.status, "needs-recovery");
        assert!(status
            .steps
            .iter()
            .find(|step| step.id == "compare-runs")
            .expect("compare status")
            .next_safe_action
            .contains("Resolve missing prerequisites"));
        assert!(status.boundary.contains("read-only inspection"));

        let preflight = build_authoring_loop_resume_preflight_from_path(&plan_path, "compare-runs")
            .expect("resume preflight builds");
        assert_eq!(
            preflight.schema_version,
            AUTHORING_LOOP_RESUME_PREFLIGHT_SCHEMA_VERSION
        );
        assert_eq!(preflight.status, "blocked");
        assert!(preflight
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("missing artifact")));
        // A manual-action-required recovery must itself block the resume until the
        // operator resolves it, independent of any missing artifact.
        assert!(preflight
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("manual-action-required")));
        assert!(preflight.boundary.contains("does not execute"));

        fs::remove_dir_all(root).ok();
    }

    #[test]
    fn loop_recovery_resume_preflight_allows_ready_pending_step_without_execution() {
        let root = unique_temp_dir("loop-recovery-ready");
        write_loop_dry_run_project(&root);
        let plan_path = write_loop_dry_run_plan(&root, "loop_project");
        let path = root.join("runs/baseline/run.json");
        fs::create_dir_all(path.parent().expect("parent")).expect("artifact dir");
        fs::write(path, "{}\n").expect("artifact");

        let preflight = build_authoring_loop_resume_preflight_from_path(&plan_path, "compare-runs")
            .expect("resume preflight builds");
        assert_eq!(preflight.status, "ready");
        assert!(preflight.blocked_reasons.is_empty());
        assert!(preflight.resume_command.command.contains("loop resume"));
        assert!(
            !root
                .join("runs/authoring-loop-ledgers/temp-loop/ledger.jsonl")
                .exists(),
            "resume preflight must not execute or write loop ledgers"
        );

        fs::remove_dir_all(root).ok();
    }

