    #[test]
    fn adversarial_input_fuzzing_plan_rejects_unbounded_or_unsupported_shapes() {
        let unbounded = include_str!(
            "../../../examples/adversarial-input-fuzzing-v1/invalid/unbounded-fuzzing-plan.json"
        );
        let error = AdversarialInputFuzzingPlanArtifact::from_json_str(unbounded)
            .expect_err("unbounded fuzzing plan rejected");
        assert!(
            error.to_string().contains("maxSteps")
                || error.to_string().contains("maxRuns")
                || error.to_string().contains("maxDurationMs")
        );

        let unsupported_action = include_str!(
            "../../../examples/adversarial-input-fuzzing-v1/invalid/unsupported-action-fuzzing-plan.json"
        );
        let error = AdversarialInputFuzzingPlanArtifact::from_json_str(unsupported_action)
            .expect_err("unsupported action rejected by schema");
        assert!(
            error.to_string().contains("execute_script")
                || error.to_string().contains("failed to parse")
        );

        let missing_blocked_reason = include_str!(
            "../../../examples/adversarial-input-fuzzing-v1/invalid/blocked-fuzzing-plan.json"
        );
        let error = AdversarialInputFuzzingPlanArtifact::from_json_str(missing_blocked_reason)
            .expect_err("blocked fuzzing plan needs reasons");
        assert!(error.to_string().contains("blockedReasons"));
    }

    #[test]
    fn adversarial_input_fuzzing_plan_hardens_budget_actions_and_expected_outputs() {
        let oversized_budget = AdversarialInputFuzzingPlanArtifact::from_json_str(
            &json!({
                "schemaVersion": "adversarial-input-fuzzing-plan-v1",
                "planId": "qa14_3_oversized_budget",
                "runId": "run_fuzzing_plan_smoke",
                "inputDomain": {
                    "domainId": "movement-buttons",
                    "scenarioId": "collect-and-exit",
                    "scenarioCandidateRef": "evidence/scenarios/collect-and-exit/scenario-candidate.json",
                    "allowedKeys": ["left", "right"]
                },
                "deterministicSeed": 7,
                "budget": { "maxSteps": 1001, "maxRuns": 1, "maxDurationMs": 2000, "maxArtifacts": 4, "maxOutputBytes": 65536 },
                "actionSet": ["press_key", "release_key"],
                "constraints": [{ "constraintId": "bounded-local-only", "description": "Use deterministic local evidence only." }],
                "stopCondition": { "conditionId": "budget-only", "description": "Stop at the declared budget." },
                "expectedEvidence": [{ "evidenceId": "seeded-inputs", "artifactKind": "fuzz_input", "pathHint": "evidence/fuzz/qa14_3_oversized_budget/fuzz-inputs.json" }],
                "outputRoot": "evidence/fuzz/qa14_3_oversized_budget/",
                "cleanupPolicy": { "mode": "retain_on_failure" },
                "status": "planned"
            })
            .to_string(),
        )
        .expect_err("oversized maxSteps rejected");
        assert!(oversized_budget.to_string().contains("maxSteps"));

        let replay_without_ref = AdversarialInputFuzzingPlanArtifact::from_json_str(
            &json!({
                "schemaVersion": "adversarial-input-fuzzing-plan-v1",
                "planId": "qa14_3_replay_without_ref",
                "runId": "run_fuzzing_plan_smoke",
                "inputDomain": {
                    "domainId": "movement-buttons",
                    "scenarioId": "collect-and-exit",
                    "scenarioCandidateRef": "evidence/scenarios/collect-and-exit/scenario-candidate.json",
                    "allowedKeys": ["left", "right"]
                },
                "deterministicSeed": 7,
                "budget": { "maxSteps": 8, "maxRuns": 1, "maxDurationMs": 2000, "maxArtifacts": 4, "maxOutputBytes": 65536 },
                "actionSet": ["press_key", "replay_step"],
                "constraints": [{ "constraintId": "bounded-local-only", "description": "Use deterministic local evidence only." }],
                "stopCondition": { "conditionId": "budget-only", "description": "Stop at the declared budget." },
                "expectedEvidence": [{ "evidenceId": "seeded-inputs", "artifactKind": "fuzz_input", "pathHint": "evidence/fuzz/qa14_3_replay_without_ref/fuzz-inputs.json" }],
                "outputRoot": "evidence/fuzz/qa14_3_replay_without_ref/",
                "cleanupPolicy": { "mode": "retain_on_failure" },
                "status": "planned"
            })
            .to_string(),
        )
        .expect_err("replay_step requires replay evidence ref");
        assert!(replay_without_ref.to_string().contains("replayEvidenceRef"));

        let duplicate_output = AdversarialInputFuzzingPlanArtifact::from_json_str(
            &json!({
                "schemaVersion": "adversarial-input-fuzzing-plan-v1",
                "planId": "qa14_3_duplicate_output",
                "runId": "run_fuzzing_plan_smoke",
                "inputDomain": {
                    "domainId": "movement-buttons",
                    "scenarioId": "collect-and-exit",
                    "scenarioCandidateRef": "evidence/scenarios/collect-and-exit/scenario-candidate.json",
                    "allowedKeys": ["left", "right"]
                },
                "deterministicSeed": 7,
                "budget": { "maxSteps": 8, "maxRuns": 1, "maxDurationMs": 2000, "maxArtifacts": 4, "maxOutputBytes": 65536 },
                "actionSet": ["press_key", "release_key"],
                "constraints": [{ "constraintId": "bounded-local-only", "description": "Use deterministic local evidence only." }],
                "stopCondition": { "conditionId": "budget-only", "description": "Stop at the declared budget." },
                "expectedEvidence": [
                    { "evidenceId": "seeded-inputs", "artifactKind": "fuzz_input", "pathHint": "evidence/fuzz/qa14_3_duplicate_output/fuzz-inputs.json" },
                    { "evidenceId": "seeded-inputs-copy", "artifactKind": "fuzz_summary", "pathHint": "evidence/fuzz/qa14_3_duplicate_output/fuzz-inputs.json" }
                ],
                "outputRoot": "evidence/fuzz/qa14_3_duplicate_output/",
                "cleanupPolicy": { "mode": "retain_on_failure" },
                "status": "planned"
            })
            .to_string(),
        )
        .expect_err("duplicate expected output paths are rejected");
        assert!(duplicate_output.to_string().contains("pathHint"));
    }

    #[test]
    fn adversarial_input_fuzzing_plan_ref_validation_accepts_indexed_candidate_and_replay() {
        let (root, artifacts) = create_test_run("fuzzing-plan-refs");
        let mut plan = AdversarialInputFuzzingPlanArtifact::from_json_str(include_str!(
            "../../../examples/adversarial-input-fuzzing-v1/fuzzing-plan.sample.json"
        ))
        .expect("fixture parses");
        let run = read_json_value(artifacts.run_dir.join("run.json")).expect("run reads");
        plan.run_id = json_string(&run, "id").expect("run id present");

        for reference in [
            plan.input_domain.scenario_candidate_ref.as_deref().unwrap(),
            plan.input_domain.replay_evidence_ref.as_deref().unwrap(),
        ] {
            fs::create_dir_all(
                artifacts
                    .run_dir
                    .join(Path::new(reference).parent().unwrap()),
            )
            .expect("reference parent exists");
            write_json(
                &artifacts.run_dir.join(reference),
                &json!({
                    "runId": plan.run_id,
                    "scenarioId": plan.input_domain.scenario_id,
                    "targetId": plan.input_domain.domain_id,
                    "artifact": "fuzz_link_fixture"
                }),
            )
            .expect("reference writes");
            add_evidence_artifact(
                &artifacts.run_dir,
                &format!("fuzz-link-{}", reference.replace('/', "-")),
                "application/json",
                reference,
                json!({ "artifact": "fuzz_link_fixture" }),
            )
            .expect("reference indexed");
        }

        validate_adversarial_input_fuzzing_plan_refs(&artifacts.run_dir, &plan)
            .expect("fresh indexed candidate/replay refs validate");

        let replay_ref = plan.input_domain.replay_evidence_ref.as_deref().unwrap();
        write_json(
            &artifacts.run_dir.join(replay_ref),
            &json!({
                "runId": "stale-run",
                "scenarioId": plan.input_domain.scenario_id,
                "targetId": plan.input_domain.domain_id,
                "artifact": "fuzz_link_fixture"
            }),
        )
        .expect("stale replay writes");
        let stale = validate_adversarial_input_fuzzing_plan_refs(&artifacts.run_dir, &plan)
            .expect_err("stale replay refs rejected");
        assert!(stale.to_string().contains("stale"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

