        assert_eq!(artifact.status, AgentGeneratedLevelDraftStatus::Drafted);
        assert_eq!(
            artifact.draft_kind,
            AgentGeneratedLevelDraftKind::CompleteLevel
        );
        assert!(artifact.author.untrusted);
