    #[test]
    fn runtime_invariant_evidence_rejects_silent_or_unsafe_results() {
        let base = |check: serde_json::Value| {
            json!({
                "schemaVersion":"runtime-invariant-evidence-v1",
                "modelId":"qa14_5_runtime_invariants",
                "runId":"run_qa_invariant_smoke",
                "worldStatePath":"evidence/scenarios/collect-and-exit/world-state.json",
                "recordedAtUnixMs":1700000000000_u64,
                "checks":[check]
            })
        };

        let missing_message = RuntimeInvariantEvidence::from_json_str(&base(json!({
            "invariantId":"health-non-negative","invariantType":"health_non_negative","status":"failed","targetPath":"player.health","evidenceRefs":["evidence/scenarios/collect-and-exit/world-state.json"],"observed":-1
        })).to_string()).expect_err("failed checks require message");
        assert!(missing_message.to_string().contains("requires message"));

        let passing_with_message = RuntimeInvariantEvidence::from_json_str(&base(json!({
            "invariantId":"player-in-bounds","invariantType":"player_in_bounds","status":"passed","targetPath":"player.transform","evidenceRefs":["evidence/scenarios/collect-and-exit/world-state.json"],"message":"passed but maybe stale"
        })).to_string()).expect_err("passing checks cannot hide caveats in message");
        assert!(passing_with_message
            .to_string()
            .contains("must not include message"));

        let unsafe_ref = RuntimeInvariantEvidence::from_json_str(&base(json!({
            "invariantId":"player-in-bounds","invariantType":"player_in_bounds","status":"passed","targetPath":"player.transform","evidenceRefs":["../world-state.json"]
        })).to_string()).expect_err("escaping evidence ref rejected");
        assert!(
            unsafe_ref.to_string().contains("escape")
                || unsafe_ref.to_string().contains("evidence/")
        );

        let backslash_escape = RuntimeInvariantEvidence::from_json_str(&base(json!({
            "invariantId":"player-in-bounds","invariantType":"player_in_bounds","status":"passed","targetPath":"player.transform","evidenceRefs":["invariants/..\\secret.json"]
        })).to_string()).expect_err("backslash escape under invariants/ rejected");
        assert!(backslash_escape.to_string().contains("backslash"));
    }

    #[test]
    fn runtime_invariant_evidence_ref_rejects_backslash_and_repeated_separators() {
        // Pre-existing ignored run evidence shapes that Path::components() would
        // normalize away on Unix must fail closed for the invariants/ subtree.
        validate_runtime_invariant_evidence_ref("invariants/manual-placeholder.json")
            .expect("plain run-relative invariants/ ref is accepted");

        let backslash = validate_runtime_invariant_evidence_ref("invariants/..\\secret.json")
            .expect_err("backslash parent segment rejected");
        assert!(backslash.to_string().contains("backslash"));

        let mixed_backslash =
            validate_runtime_invariant_evidence_ref("invariants/nested\\child.json")
                .expect_err("any backslash separator rejected");
        assert!(mixed_backslash.to_string().contains("backslash"));

        let repeated = validate_runtime_invariant_evidence_ref("invariants//child.json")
            .expect_err("repeated separators rejected");
        assert!(repeated.to_string().contains("repeated"));

        let parent = validate_runtime_invariant_evidence_ref("invariants/../secret.json")
            .expect_err("parent segment rejected");
        assert!(parent.to_string().contains("escape"));
    }

    #[test]
    fn runtime_invariant_evaluator_reports_pass_fail_and_unsupported_checks() {
        let model = RuntimeInvariantModel::from_json_str(
            &json!({
                "schemaVersion": "runtime-invariant-model-v1",
                "modelId": "qa14_5_runtime_invariants_eval",
                "runId": "run_qa_invariant_eval",
                "scenarioId": "collect-and-exit",
                "worldStatePath": "evidence/scenarios/collect-and-exit/world-state.json",
                "scenarioResultPath": "evidence/scenarios/collect-and-exit/scenario-result.json",
                "evidenceIndexPath": "evidence/index.json",
                "invariants": [
                    {
                        "invariantId": "player-in-bounds",
                        "invariantType": "player_in_bounds",
                        "targetPath": "player.transform",
                        "boundsPath": "level.bounds",
                        "evidencePath": "evidence/scenarios/collect-and-exit/world-state.json"
                    },
                    {
                        "invariantId": "health-non-negative",
                        "invariantType": "health_non_negative",
                        "targetPath": "player.health",
                        "evidencePath": "evidence/scenarios/collect-and-exit/world-state.json"
                    },
                    {
                        "invariantId": "manual-placeholder",
                        "invariantType": "no_impossible_state",
                        "targetPath": "world.impossible",
                        "evidencePath": "invariants/manual-placeholder.json"
                    }
                ]
            })
            .to_string(),
        )
        .expect("model parses");

        let evidence = evaluate_runtime_invariants(
            &model,
            &json!({
                "player": { "transform": { "x": 4, "y": 5 }, "health": -1 },
                "level": { "bounds": { "minX": 0, "maxX": 10, "minY": 0, "maxY": 10 } }
            }),
            Some(&json!({ "scenario_id": "collect-and-exit", "status": "failed" })),
            1700000000000,
        )
        .expect("evaluation emits valid evidence");

        assert_eq!(evidence.checks.len(), 3);
        assert_eq!(evidence.checks[0].status, RuntimeInvariantStatus::Passed);
        assert_eq!(evidence.checks[1].status, RuntimeInvariantStatus::Failed);
        assert_eq!(
            evidence.checks[2].status,
            RuntimeInvariantStatus::Unsupported
        );
        let summary = evidence.summary();
        assert_eq!(summary.passed_count, 1);
        assert_eq!(summary.failed_count, 1);
        assert_eq!(summary.unsupported_count, 1);
    }

