    #[test]
    fn project_asset_manifest_v1_rejects_invalid_paths_roots_extensions_and_hashes() {
        let root = unique_temp_dir("project-asset-manifest-invalid");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("runs/previews")).expect("runs dir");
        fs::write(root.join("assets/sprites/player.png"), b"png fixture").expect("sprite");
        fs::write(root.join("runs/previews/player.png"), b"generated fixture").expect("generated");
        let sprite_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("sprite hashes");
        let generated_hash = hash_project_asset_file(root.join("runs/previews/player.png"))
            .expect("generated hashes");

        let manifest_with_path =
            |path: &str,
             asset_type: ProjectAssetType,
             hash: ProjectAssetContentHash,
             classification: ProjectAssetClassification| {
                ProjectAssetManifest::from_json_str(
                    &json!({
                        "schemaVersion": "asset-manifest-v1",
                        "id": "invalid_asset_fixture",
                        "assets": [{
                            "id": "asset",
                            "type": asset_type,
                            "path": path,
                            "contentHash": hash,
                            "classification": classification
                        }]
                    })
                    .to_string(),
                )
                .expect("manifest parses")
            };

        let absolute = manifest_with_path(
            "/tmp/player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = absolute
            .validate_assets(&root)
            .expect_err("absolute path rejected");
        assert!(rejected.to_string().contains("must be relative"));

        let escape = manifest_with_path(
            "../player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = escape
            .validate_assets(&root)
            .expect_err("path escape rejected");
        assert!(rejected.to_string().contains("project root"));

        let hidden = manifest_with_path(
            ".omx/player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = hidden
            .validate_assets(&root)
            .expect_err("hidden root rejected");
        assert!(rejected.to_string().contains("hidden"));

        let generated_source = manifest_with_path(
            "runs/previews/player.png",
            ProjectAssetType::Image,
            generated_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = generated_source
            .validate_assets(&root)
            .expect_err("source generated root rejected");
        assert!(rejected.to_string().contains("generated root runs"));

        let unsupported = manifest_with_path(
            "assets/sprites/player.txt",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = unsupported
            .validate_assets(&root)
            .expect_err("unsupported extension rejected");
        assert!(rejected.to_string().contains("unsupported extension"));

        let missing = manifest_with_path(
            "assets/sprites/missing.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = missing
            .validate_assets(&root)
            .expect_err("missing rejected");
        assert!(rejected.to_string().contains("missing file"));

        let mut stale_hash = sprite_hash.clone();
        stale_hash.value = "0000000000000000".to_string();
        let stale = manifest_with_path(
            "assets/sprites/player.png",
            ProjectAssetType::Image,
            stale_hash,
            ProjectAssetClassification::SourceLike,
        );
        let rejected = stale
            .validate_assets(&root)
            .expect_err("stale hash rejected");
        assert!(rejected.to_string().contains("contentHash mismatch"));

        let generated = manifest_with_path(
            "runs/previews/player.png",
            ProjectAssetType::Image,
            generated_hash,
            ProjectAssetClassification::Generated,
        );
        generated
            .validate_assets(&root)
            .expect("generated classified asset may live under generated root");

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn source_file_class_v1_classifies_fixture_matrix() {
        let fixture_path = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../../examples/source-file-class-v1/classification-cases.json");
        let fixture: serde_json::Value = serde_json::from_str(
            &fs::read_to_string(fixture_path).expect("classification fixture reads"),
        )
        .expect("classification fixture parses");
        assert_eq!(
            fixture
                .get("schemaVersion")
                .and_then(|value| value.as_str()),
            Some("source-file-class-fixture-v1")
        );
        let cases = fixture
            .get("cases")
            .and_then(|value| value.as_array())
            .expect("cases array");
        assert!(cases.len() >= 10, "fixture covers the source class matrix");
        for case in cases {
            let path = case
                .get("path")
                .and_then(|value| value.as_str())
                .expect("case path");
            let expected_class = case
                .get("class")
                .and_then(|value| value.as_str())
                .expect("case class");
            let expected_decision = case
                .get("decision")
                .and_then(|value| value.as_str())
                .expect("case decision");
            let report = classify_source_file_path_str(path);
            assert_eq!(report.schema_version, "source-file-class-v1");
            assert_eq!(
                serde_json::to_value(&report.class).expect("class serializes"),
                json!(expected_class),
                "class for {path}"
            );
            assert_eq!(
                serde_json::to_value(&report.decision).expect("decision serializes"),
                json!(expected_decision),
                "decision for {path}"
            );
            assert!(
                report
                    .guardrails
                    .iter()
                    .any(|guardrail| guardrail.contains("no source patch apply")),
                "guardrail for {path}"
            );
            if report.is_blocked() {
                assert!(
                    !report.blocked_reasons.is_empty(),
                    "blocked class should explain why: {path}"
                );
            }
        }
    }

    #[test]
    fn source_file_class_v1_rejects_unsafe_hidden_generated_and_opaque_paths() {
        let unsafe_absolute = classify_source_file_path_str("/tmp/Ouroforge/README.md");
        assert_eq!(unsafe_absolute.class, SourceFileClassLabel::UnsafePath);
        assert!(unsafe_absolute.is_blocked());
        assert!(unsafe_absolute
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("absolute")));

        let generated = classify_source_file_path_str("target/debug/build.log");
        assert_eq!(generated.class, SourceFileClassLabel::GeneratedLocalState);
        assert!(generated.is_blocked());
        assert!(generated
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("generated")));

        let hidden_nested = classify_source_file_path_str("examples/demo/.cache/state.json");
        assert_eq!(hidden_nested.class, SourceFileClassLabel::UnsafePath);
        assert!(hidden_nested.is_blocked());

        let opaque = classify_source_file_path_str("examples/assets/player.png");
        assert_eq!(opaque.class, SourceFileClassLabel::BinaryOpaque);
        assert!(opaque.is_blocked());

        // Repeated separators must stay unsafe-path: `Path::components()` collapses
        // `//`, so the guard must inspect the raw separator-split segments.
        let repeated_separator =
            classify_source_file_path_str("examples//playable-demo-v2/scenes/foo.scene.json");
        assert_eq!(repeated_separator.class, SourceFileClassLabel::UnsafePath);
        assert!(repeated_separator.is_blocked());
        assert!(repeated_separator
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("empty path component")));

        // Backslash-normalized repeated separators are equally unsafe.
        let backslash_repeated = classify_source_file_path_str("examples\\\\demo\\scene.json");
        assert_eq!(backslash_repeated.class, SourceFileClassLabel::UnsafePath);
        assert!(backslash_repeated.is_blocked());

        // Trailing separator leaves an empty final segment and must be rejected.
        let trailing_separator = classify_source_file_path_str("examples/demo/scene.json/");
        assert_eq!(trailing_separator.class, SourceFileClassLabel::UnsafePath);
        assert!(trailing_separator.is_blocked());
    }

    #[test]
    fn source_patch_target_class_validation_blocks_dependency_ci_scripts_and_generated_roots() {
        let validation = classify_source_patch_preview_targets([
            "seeds/platformer.yaml",
            "Cargo.toml",
            ".github/workflows/ci.yml",
            "build.rs",
            "scripts/check.sh",
            "runs/run-1/run.json",
            "target/debug/output.txt",
            "examples/demo/.cache/state.json",
            "examples/assets/player.png",
        ]);
        assert_eq!(
            validation.schema_version,
            "source-patch-target-class-validation-v1"
        );
        assert_eq!(validation.status, "blocked");
        assert!(validation.has_blocked_targets());
        assert!(validation
            .guardrails
            .iter()
            .any(|guardrail| guardrail.contains("no diff evaluation")));
        for expected in [
            "Cargo.toml",
            ".github/workflows/ci.yml",
            "build.rs",
            "scripts/check.sh",
            "runs/run-1/run.json",
            "target/debug/output.txt",
            "examples/demo/.cache/state.json",
            "examples/assets/player.png",
        ] {
            assert!(
                validation
                    .blocked_reasons
                    .iter()
                    .any(|reason| reason.contains(expected)),
                "missing blocked reason for {expected}: {:?}",
                validation.blocked_reasons
            );
        }
        let error = validate_source_patch_preview_targets(["seeds/platformer.yaml", "Cargo.lock"])
            .expect_err("blocked target rejects preview preflight");
        assert!(error
            .to_string()
            .contains("source patch preview target class validation blocked"));
        assert!(error.to_string().contains("Cargo.lock"));
    }

    #[test]
    fn source_patch_target_class_validation_serializes_report_shape() {
        let validation = classify_source_patch_preview_targets([
            "seeds/platformer.yaml",
            "docs/source-file-class-validator-v1.md",
            "Cargo.lock",
        ]);
        let value = serde_json::to_value(&validation).expect("validation serializes");
        assert_eq!(
            value["schemaVersion"],
            json!("source-patch-target-class-validation-v1")
        );
        assert_eq!(value["status"], json!("blocked"));
        assert!(value["targets"]
            .as_array()
            .is_some_and(|targets| targets.len() == 3));
        assert_eq!(
            value["targets"][0]["schemaVersion"],
            json!("source-file-class-v1")
        );
        assert_eq!(value["targets"][0]["decision"], json!("allowed"));
        assert_eq!(value["targets"][1]["decision"], json!("needs-approval"));
        assert_eq!(value["targets"][2]["class"], json!("dependency-manifest"));
        assert!(value["blockedReasons"][0]
            .as_str()
            .is_some_and(|reason| reason.contains("Cargo.lock")));
        assert!(value["guardrails"]
            .as_array()
            .expect("guardrails")
            .iter()
            .any(|guardrail| guardrail
                .as_str()
                .is_some_and(|text| text.contains("no diff evaluation"))));
    }

