    struct SuiteScenarioTransport {
        calls: Vec<String>,
    }

    impl CdpTransport for SuiteScenarioTransport {
        fn send_command(
            &mut self,
            method: &str,
            params: serde_json::Value,
        ) -> Result<serde_json::Value> {
            match method {
                "Runtime.evaluate" => {
                    let expression = params["expression"]
                        .as_str()
                        .expect("expression present")
                        .to_string();
                    self.calls.push(expression.clone());
                    let value = if expression.contains("typeof window.__OUROFORGE__.step") {
                        json!(true)
                    } else if expression.contains("getWorldState") {
                        json!({ "object": { "x": 32 } })
                    } else if expression.contains("getFrameStats") {
                        json!({ "fixedDeltaMs": 16 })
                    } else if expression.contains("__OUROFORGE_CONSOLE__") {
                        json!([])
                    } else {
                        json!({})
                    };
                    Ok(json!({ "result": { "value": value } }))
                }
                "Performance.enable" => Ok(json!({})),
                "Performance.getMetrics" => Ok(json!({ "metrics": [] })),
                _ => Ok(json!({})),
            }
        }
    }

    struct TransitionScenarioTransport {
        calls: Vec<(String, bool)>,
    }

    impl CdpTransport for TransitionScenarioTransport {
        fn send_command(
            &mut self,
            method: &str,
            params: serde_json::Value,
        ) -> Result<serde_json::Value> {
            match method {
                "Runtime.evaluate" => {
                    let expression = params["expression"]
                        .as_str()
                        .expect("expression present")
                        .to_string();
                    let await_promise = params["awaitPromise"].as_bool().unwrap_or(false);
                    self.calls.push((expression.clone(), await_promise));
                    let value = if expression.contains("typeof window.__OUROFORGE__.transition") {
                        json!(true)
                    } else if expression.contains("transition(\"to_level_2\")") {
                        json!({
                            "sceneId": "level-2",
                            "transitionEvents": [{
                                "status": "succeeded",
                                "id": "to_level_2",
                                "fromSceneId": "level-1",
                                "toSceneId": "level-2",
                                "toScene": "scenes/level-2.scene.json"
                            }]
                        })
                    } else if expression.contains("getWorldState") {
                        json!({
                            "sceneId": "level-2",
                            "sceneTransitions": [],
                            "transitionEvents": [{
                                "status": "succeeded",
                                "id": "to_level_2",
                                "fromSceneId": "level-1",
                                "toSceneId": "level-2",
                                "toScene": "scenes/level-2.scene.json"
                            }]
                        })
                    } else if expression.contains("getFrameStats") {
                        json!({ "fixedDeltaMs": 16, "tick": 0 })
                    } else if expression.contains("getEvents") {
                        json!({ "events": [{ "type": "runtime.scene.transition.succeeded" }] })
                    } else if expression.contains("__OUROFORGE_CONSOLE__") {
                        json!([])
                    } else {
                        json!({})
                    };
                    Ok(json!({ "result": { "value": value } }))
                }
                "Performance.enable" => Ok(json!({})),
                "Performance.getMetrics" => Ok(json!({ "metrics": [] })),
                _ => Ok(json!({})),
            }
        }
    }

    #[test]
    fn scenario_transition_step_records_transition_evidence() {
        let (root, artifacts) = create_test_run("ouroforge-scenario-transition-evidence");
        let seed = Seed::from_yaml_str(
            r#"
id: transition-scenario.v1
title: Transition Scenario Fixture
goal: Verify transition evidence.
constraints:
  target: game-runtime
acceptance:
  - Transition evidence is assertion-addressable.
scenarios:
  - id: transition-smoke
    description: Drive a declared scene transition.
    steps:
      - transition:
          id: to_level_2
    assertions:
      - world_state:
          path: sceneId
          equals: level-2
      - transition_evidence:
          path: 0.status
          equals: succeeded
      - transition_evidence:
          path: 0.toSceneId
          equals: level-2
"#,
        )
        .expect("transition seed parses");
        let config = ScenarioRunConfig::new(&artifacts.run_dir, "http://127.0.0.1:8080")
            .expect("scenario config");
        let mut client = CdpClient::new(TransitionScenarioTransport { calls: Vec::new() });

        let summary =
            run_scenarios_with_client(&config, &seed, &mut client).expect("scenario runs");

        assert_eq!(summary.completed, 1);
        assert_eq!(summary.passed, 1);
        let transport = client.into_transport();
        assert!(transport.calls.iter().any(|(expression, await_promise)| {
            expression == "window.__OUROFORGE__.transition(\"to_level_2\")" && *await_promise
        }));
        let result = read_json_value(artifacts.run_dir.join(&summary.result_paths[0]))
            .expect("scenario result reads");
        assert_eq!(result["status"], "passed");
        let transition_path = result["evidence"]["transition_evidence"]
            .as_str()
            .expect("transition evidence path");
        let transition_evidence =
            read_json_value(artifacts.run_dir.join(transition_path)).expect("transition evidence");
        assert_eq!(transition_evidence["bounded"], true);
        assert_eq!(transition_evidence["currentSceneId"], "level-2");
        assert_eq!(
            transition_evidence["transitionEvents"][0]["id"],
            "to_level_2"
        );
        assert!(result["assertions"]
            .as_array()
            .expect("assertions")
            .iter()
            .any(|assertion| assertion["target"] == "transition_evidence"
                && assertion["passed"] == true
                && assertion["evidence_ref"] == transition_path));
        fs::remove_dir_all(root).ok();
    }

    struct MalformedProbeScenarioTransport;

    impl CdpTransport for MalformedProbeScenarioTransport {
        fn send_command(
            &mut self,
            method: &str,
            params: serde_json::Value,
        ) -> Result<serde_json::Value> {
            match method {
                "Runtime.evaluate" => {
                    let expression = params["expression"].as_str().unwrap_or_default();
                    if expression.contains("getWorldState") {
                        Ok(json!({ "result": { "value": "not-a-world-state-object" } }))
                    } else {
                        Ok(json!({ "result": { "value": {} } }))
                    }
                }
                _ => Ok(json!({})),
            }
        }
    }

    #[test]
    fn scenario_malformed_runtime_probe_records_failure_evidence() {
        let (root, artifacts) = create_test_run("ouroforge-scenario-malformed-runtime-probe");
        let seed = Seed::from_yaml_str(
            r#"
id: malformed-probe.v1
title: Malformed Probe Fixture
goal: Fail with explicit probe contract evidence.
constraints:
  target: file-harness
acceptance:
  - Runtime probe failure is explicit.
scenarios:
  - id: malformed-probe
    description: Runtime world state is malformed.
    assertions:
      - world_state:
          path: object.x
          equals: 32
"#,
        )
        .expect("seed parses");
        let config = ScenarioRunConfig::new(&artifacts.run_dir, "http://127.0.0.1:8080")
            .expect("scenario config");
        let mut client = CdpClient::new(MalformedProbeScenarioTransport);

        let summary = run_scenarios_with_client(&config, &seed, &mut client)
            .expect("suite records probe failure instead of aborting");

        assert_eq!(summary.completed, 1);
        assert_eq!(summary.passed, 0);
        assert_eq!(summary.failed, 1);
        let failure_path = summary
            .evidence_paths
            .iter()
            .find(|path| path.contains("runtime-probe-contract-failure"))
            .expect("probe contract failure evidence path");
        let failure = read_json_value(artifacts.run_dir.join(failure_path))
            .expect("probe failure evidence reads");
        assert_eq!(failure["artifact"], "runtime_probe_contract_failure");
        assert_eq!(failure["method"], "getWorldState");
        assert_eq!(
            failure["probe_contract"]["version"],
            RUNTIME_PROBE_CONTRACT_VERSION
        );
        assert!(failure["error"]
            .as_str()
            .expect("error text")
            .contains("malformed response"));
        let result = read_json_value(artifacts.run_dir.join(&summary.result_paths[0]))
            .expect("scenario result reads");
        assert_eq!(result["status"], "failed");
        assert_eq!(
            result["evidence"]["runtime_probe_contract_failure"],
            json!(failure_path)
        );
        let events = read_ledger_events(&artifacts.run_dir).expect("ledger reads");
        assert!(events.iter().any(|event| {
            event["event"] == "scenario.probe_contract_failed"
                && event["payload"]["probe_call"] == "getWorldState"
        }));
        fs::remove_dir_all(root).ok();
    }

    #[test]
    fn suite_execution_preserves_document_order_and_failure_isolation() {
        let (root, artifacts) = create_test_run("ouroforge-suite-order-test");
        let seed = Seed::from_yaml_str(
            r#"
id: suite.v1
title: Suite Fixture
goal: Run multiple scenarios deterministically.
constraints:
  target: file-harness
acceptance:
  - Preserve scenario evidence.
scenarios:
  - id: first-pass
    description: First scenario passes.
    assertions:
      - world_state:
          path: object.x
          equals: 32
  - id: second-fail
    description: Second scenario fails without removing first evidence.
    assertions:
      - world_state:
          path: object.x
          equals: 999
"#,
        )
        .expect("suite seed parses");
        let config = ScenarioRunConfig::new(&artifacts.run_dir, "http://127.0.0.1:8080")
            .expect("scenario config");
        let mut client = CdpClient::new(SuiteScenarioTransport { calls: Vec::new() });

        let summary = run_scenarios_with_client(&config, &seed, &mut client).expect("suite runs");

        assert_eq!(summary.scenario_order, vec!["first-pass", "second-fail"]);
        assert_eq!(summary.completed, 2);
        assert_eq!(summary.passed, 1);
        assert_eq!(summary.failed, 1);
        assert_eq!(summary.result_paths.len(), 2);
        assert!(artifacts
            .run_dir
            .join(&summary.suite_summary_path)
            .is_file());
        let suite_summary = read_json_value(artifacts.run_dir.join(&summary.suite_summary_path))
            .expect("suite summary reads");
        assert_eq!(suite_summary["status"], "failed");
        assert_eq!(
            suite_summary["scenario_order"],
            json!(["first-pass", "second-fail"])
        );
        assert_eq!(
            suite_summary["scenario_results"].as_array().unwrap().len(),
            2
        );
        assert!(summary
            .result_paths
            .iter()
            .any(|path| path.contains("first-pass")));
        assert!(summary
            .result_paths
            .iter()
            .any(|path| path.contains("second-fail")));
        assert!(artifacts
            .run_dir
            .join("evidence/scenarios/first-pass")
            .is_dir());
        assert!(artifacts
            .run_dir
            .join("evidence/scenarios/second-fail")
            .is_dir());
        fs::remove_dir_all(root).ok();
    }

    #[test]
    fn scenario_run_emits_deterministic_input_replay_artifacts() {
        let (root, artifacts) = create_test_run("ouroforge-scenario-input-replay-artifacts");
        let seed = Seed::from_yaml_str(
            r#"
id: replay-artifact.v1
title: Replay Artifact Fixture
goal: Emit deterministic replay artifacts.
constraints:
  target: file-harness
acceptance:
  - Preserve scenario input replay evidence.
scenarios:
  - id: replay-smoke
    description: Scenario with direct input and inline replay.
    steps:
      - wait:
          frames: 2
      - input:
          right: true
      - replay:
          schemaVersion: "1"
          id: move-left
          events:
            - frame: 0
              key: left
              pressed: true
            - frame: 3
              key: left
              pressed: false
"#,
        )
        .expect("seed parses");
        let config = ScenarioRunConfig::new(&artifacts.run_dir, "http://127.0.0.1:8080")
            .expect("scenario config");
        let mut client = CdpClient::new(SuiteScenarioTransport { calls: Vec::new() });

        let summary =
            run_scenarios_with_client(&config, &seed, &mut client).expect("scenario runs");

        assert_eq!(summary.passed, 1);
        let result_path = summary.result_paths.first().expect("result path exists");
        let result = read_json_value(artifacts.run_dir.join(result_path)).expect("result reads");
        let deterministic_replays = result["evidence"]["scenario_input_replays"]
            .as_array()
            .expect("scenario input replays listed");
        assert_eq!(deterministic_replays.len(), 3);
        assert_eq!(
            result["evidence"]["input_replays"]
                .as_array()
                .unwrap()
                .len(),
            4
        );

        let first_path = deterministic_replays[0]
            .as_str()
            .expect("first replay path is string");
        let first_artifact: ScenarioInputReplayArtifact = serde_json::from_value(
            read_json_value(artifacts.run_dir.join(first_path)).expect("replay artifact reads"),
        )
        .expect("replay artifact parses");
        first_artifact
            .validate()
            .expect("replay artifact validates");
        assert_eq!(
            first_artifact.schema_version,
            SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION
        );
        assert_eq!(first_artifact.scenario_id, "replay-smoke");
        assert_eq!(first_artifact.step_index, 1);
        assert_eq!(first_artifact.frame, 2);
        assert_eq!(first_artifact.action.kind, "scenario_input_step");
        assert_eq!(first_artifact.input.right, Some(true));
        assert_eq!(
            first_artifact
                .probe
                .as_ref()
                .and_then(|probe| probe.world_state_path.as_deref()),
            result["evidence"]["world_state"].as_str()
        );
        assert_eq!(
            first_artifact
                .result
                .as_ref()
                .map(|result| result.scenario_result_path.as_str()),
            Some(result_path.as_str())
        );

        let replay_artifacts = read_evidence_index(&artifacts.run_dir)
            .expect("evidence index reads")
            .artifacts
            .into_iter()
            .filter(|artifact| {
                artifact
                    .metadata
                    .get("artifact")
                    .and_then(|value| value.as_str())
                    == Some("scenario_input_replay")
            })
            .collect::<Vec<_>>();
        assert_eq!(replay_artifacts.len(), 3);
        fs::remove_dir_all(root).ok();
    }

